// ============================================================
// Free version - raw diff alerts only. For AI-written summaries and
// CSS selector targeting, see the Pro version:
// https://rubenfabioux.vercel.app
// ============================================================
// CONFIGURATION - this is the ONLY place to edit
// ============================================================

// 1) Paste your Discord or Slack webhook URL here
const WEBHOOK_URL = "PASTE_YOUR_WEBHOOK_URL_HERE";

// 2) List of competitor pages to watch
const TARGETS = [
  { name: "Competitor A - Pricing", url: "https://example.com/pricing" },
  { name: "Competitor B - Blog",    url: "https://example.org/blog" }
];

// ============================================================
return TARGETS.map(t => ({ json: { ...t, webhookUrl: WEBHOOK_URL } }));

// Get the matching target config
const target = $('Targets').item.json;
const sd = $getWorkflowStaticData('global');
sd.pages = sd.pages || {};

// --- Network error / site blocking the request ---
if ($json.error) {
  const msg = `⚠️ **${target.name}** - could not fetch the page.\n${target.url}\nError: ${$json.error.message || 'unknown'}`;
  return { json: { ...target, notify: true, message: msg } };
}

// --- HTML cleanup -> plain text ---
let html = String($json.data || '');
html = html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
  .replace(/<[^>]+>/g, '\n');
let text = html
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/gi, '&')
  .replace(/&#\d+;/g, ' ')
  .replace(/[ \t]+/g, ' ');
const lines = text.split('\n').map(l => l.trim()).filter(l => l.length > 2);
text = lines.join('\n');

// --- FNV-1a hash (pure JS, no dependency) ---
let h = 2166136261;
for (let i = 0; i < text.length; i++) {
  h ^= text.charCodeAt(i);
  h = Math.imul(h, 16777619);
}
const hash = (h >>> 0).toString(16);

const prev = sd.pages[target.name];
sd.pages[target.name] = { hash, text, lastChecked: new Date().toISOString() };

// --- First run: store baseline, no alert ---
if (!prev) {
  return { json: { ...target, notify: false, firstRun: true } };
}

// --- No change ---
if (prev.hash === hash) {
  return { json: { ...target, notify: false } };
}

// --- Change detected: line-by-line diff ---
const oldLines = new Set(prev.text.split('\n'));
const newLines = new Set(text.split('\n'));
const added = [...newLines].filter(l => !oldLines.has(l)).slice(0, 15);
const removed = [...oldLines].filter(l => !newLines.has(l)).slice(0, 15);

// Clean truncation: cut at the last word/line boundary before max, add ... if truncated
function clip(s, max) {
  s = String(s == null ? '' : s);
  if (s.length <= max) return s;
  var cut = s.slice(0, max - 1);
  var nl = cut.lastIndexOf(String.fromCharCode(10));
  var sp = cut.lastIndexOf(' ');
  var b = Math.max(nl, sp);
  if (b > max * 0.6) cut = cut.slice(0, b);
  return cut.trimEnd() + String.fromCharCode(8230);
}

let msg = `🔔 **${target.name}** has changed!\n${target.url}\n`;
if (added.length) msg += `\n➕ **New:**\n${added.map(l => '• ' + l.slice(0, 120)).join('\n')}\n`;
if (removed.length) msg += `\n➖ **Removed:**\n${removed.map(l => '• ' + l.slice(0, 120)).join('\n')}`;

return { json: { ...target, notify: true, message: clip(msg, 1900) } };
